def run_length_encode(s):
    """Encode a string as runs of consecutive characters."""
    out = []
    run_char = None
    for ch in s:
        if run_char is None:
            run_char = ch
        elif ch == run_char:
            out.append((run_char, out[-1][1] + 1))
        else:
            out.append((run_char, 1))
            run_char = ch
    out.append((run_char, out[-1][1] + 1))
    return out

def top_k_frequent(strs, k):
    """Return the k most frequent strings, ties broken alphabetically."""
    freq = {}
    for s in strs:
        freq[s] = freq.get(s, 0) + 1

    # Sort by frequency (desc) then string (asc)
    items = sorted(freq.items(), key=lambda x: (-x[1], x[0]))
    return [s for s, _ in items[:k]]

