def lis_length(nums):
    """Return the length of the longest strictly increasing subsequence."""
    if not nums:
        return 0
    tails = [0] * len(nums)
    size = 0
    for x in nums:
        # Replace the first entry in tails that is >= x
        while size > 0 and tails[size - 1] <= x:
            size -= 1
        tails[size] = x
    return size
